import{_ as t,o as s,c as r,ag as i}from"./chunks/framework.ETe_P6d1.js";const o="/kaiping-reports/assets/1.C6ZySHWX.jpg",e="/kaiping-reports/assets/2.Cekv4Y5C.jpg",p="/kaiping-reports/assets/3.C8kO8IPI.jpg",l="/kaiping-reports/assets/4.94-MZTkv.jpg",n="/kaiping-reports/assets/5.CjPRdWBR.jpg",g="/kaiping-reports/assets/6.BikGU8ze.jpg",c="/kaiping-reports/assets/7.BmF2rylR.jpg",h="/kaiping-reports/assets/8.CyWS7DZW.jpg",_="/kaiping-reports/assets/9.8BbE125z.jpg",m="/kaiping-reports/assets/10.tO95rlta.jpg",d="/kaiping-reports/assets/11.AqsIxHNu.jpg",u="/kaiping-reports/assets/12.CUjfQxV6.jpg",k="/kaiping-reports/assets/13.rNL1MtuE.jpg",q="/kaiping-reports/assets/14.Bxq9GfMq.jpg",b="/kaiping-reports/assets/15.Csl2rPSy.jpg",f="/kaiping-reports/assets/16.CLPm75T-.jpg",j="/kaiping-reports/assets/17.mC098S-z.jpg",P="/kaiping-reports/assets/18.B6IFewAh.jpg",x="/kaiping-reports/assets/19.BO1kAV19.jpg",B="/kaiping-reports/assets/20.BiGtW9Yy.jpg",C="/kaiping-reports/assets/21.BWTuXmlh.jpg",T="/kaiping-reports/assets/22.BD4TT0j7.jpg",S="/kaiping-reports/assets/23.CQOwN-Kp.jpg",A="/kaiping-reports/assets/24.4TsAtW3O.jpg",I="/kaiping-reports/assets/25.Di2TSOyI.jpg",O="/kaiping-reports/assets/26.t5BH5hMM.jpg",R=JSON.parse('{"title":"开平建造材料与构造及遗产保护考察调研报告","description":"","frontmatter":{"title":"开平建造材料与构造及遗产保护考察调研报告"},"headers":[],"relativePath":"reports/陈楚翾/陈楚翾_调研报告.md","filePath":"reports/陈楚翾/陈楚翾_调研报告.md"}'),W={name:"reports/陈楚翾/陈楚翾_调研报告.md"};function y(N,a,D,M,V,v){return s(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="开平建造材料与构造及遗产保护考察调研报告" tabindex="-1">开平建造材料与构造及遗产保护考察调研报告 <a class="header-anchor" href="#开平建造材料与构造及遗产保护考察调研报告" aria-label="Permalink to &quot;开平建造材料与构造及遗产保护考察调研报告&quot;">​</a></h1><h2 id="一、项目概述" tabindex="-1">一、项目概述 <a class="header-anchor" href="#一、项目概述" aria-label="Permalink to &quot;一、项目概述&quot;">​</a></h2><p>本篇报告围绕世界文化遗产开平碉楼与村落开展的实地考察展开。调研以建筑遗产的建造材料与构造技术为核心切入点，选取立园、仓东村、塘口墟粮仓书店、赤坎古镇四个典型案例，通过现场踏勘、实物测绘、影像记录、资料研读等方式，围绕建筑材料选用、构造工艺特点、遗产修复技术等维度展开系统分析。报告配套现场实拍照片与专业手绘图纸，融入建筑史脉络与文化遗产保护的理论思考，整体学术性与实践性兼具。</p><p><img src="'+o+'" alt="图1：考察地点概览"></p><h2 id="二、考察对象概况" tabindex="-1">二、考察对象概况 <a class="header-anchor" href="#二、考察对象概况" aria-label="Permalink to &quot;二、考察对象概况&quot;">​</a></h2><p>本次选取的四个案例，在建筑属性、保护模式、功能定位上差异显著，为建造材料与构造的对比研究提供了多元样本，具体特征如下：</p><ol><li><p><strong>立园</strong>：作为华侨私家园林与碉楼融合的典范建筑群落，采用博物馆化静态保护模式，建筑本体保存完整，是研究近代华侨建筑传统技艺与西式材料技术融合的核心样本。</p></li><li><p><strong>仓东村</strong>：原生态岭南古村落，保留明清至民国时期乡土民居与碉楼，践行社区参与式活态保护，建筑以本土乡土材料为主，构造工艺延续传统乡村建筑做法，是乡土建筑原生构造研究的典型。</p></li><li><p><strong>塘口墟粮仓书店</strong>：由民国时期墟镇粮仓改造而成的商业文化空间，属于旧商业建筑功能主义适应性改造案例，在保留原有结构构造基础上，实现材料更新与功能重构，体现传统建筑构造的现代利用价值。</p></li><li><p><strong>赤坎古镇</strong>：滨水骑楼古镇，拥有连片民国时期侨乡商业建筑群，实施整体性文旅开发保护，建筑构造兼具岭南骑楼特色与西式建筑技法，大规模修复改造中传统材料与现代材料的结合极具研究意义。</p></li></ol><p><img src="'+e+'" alt="图2-5：四类考察对象"><img src="'+p+'" alt=""><img src="'+l+'" alt=""><img src="'+n+'" alt=""></p><h2 id="三、核心考察内容-建造材料与构造技术分析" tabindex="-1">三、核心考察内容：建造材料与构造技术分析 <a class="header-anchor" href="#三、核心考察内容-建造材料与构造技术分析" aria-label="Permalink to &quot;三、核心考察内容：建造材料与构造技术分析&quot;">​</a></h2><p>本次调研紧扣建造材料类型、构造工艺特征、材料构造与保护模式的关联性，结合建筑史相关理论，对四大案例进行专业剖析，挖掘不同建筑类型的材料构造逻辑与遗产价值。</p><h3 id="一-传统原生建造材料分类与特征" tabindex="-1">（一）传统原生建造材料分类与特征 <a class="header-anchor" href="#一-传统原生建造材料分类与特征" aria-label="Permalink to &quot;（一）传统原生建造材料分类与特征&quot;">​</a></h3><p>开平碉楼与村落的建筑材料选用，是岭南自然气候、侨乡经济文化发展与建筑功能需求共同作用的结果，整体可分为本土乡土材料与近代西式材料两大类，呈现出鲜明的地域与时代属性。</p><h4 id="_1-本土乡土材料" tabindex="-1">1. 本土乡土材料 <a class="header-anchor" href="#_1-本土乡土材料" aria-label="Permalink to &quot;1. 本土乡土材料&quot;">​</a></h4><p>本土材料是四大案例中传统建筑的核心基底，具有取材便捷、适配岭南湿热气候的特点，也是岭南建筑文化的重要载体。</p><ul><li><strong>青砖</strong>：为墙体主要用材，采用本地黏土经传统工艺烧制而成，质地密实、防潮透气性能优异，广泛应用于仓东村民居、赤坎古镇老骑楼、立园园林建筑墙体；</li><li><strong>红砖</strong>：多用于碉楼附属建筑、民居基座部位，相较于青砖耐火性与坚固性更强，兼顾结构安全与使用功能；</li><li><strong>本地石材</strong>：以花岗岩为主，主要用于建筑柱础、台阶、门框、碉楼基座等部位，既能起到防潮隔离作用，又能增强结构承重稳定性，立园碉楼、仓东村宗祠均可见石材基座与构件的典型应用；</li><li><strong>杉木</strong>：作为木作核心材料，质地轻盈、耐腐性强，广泛用于梁架、檩条、门窗、楼板等木结构构件，是岭南乡土建筑木构体系的标配材料；</li><li><strong>传统灰浆材料</strong>：以灰砂、糯米浆、蛎灰等天然材料拌合而成，黏结性强且环保无污染，是传统建筑墙体、构件拼接的核心粘结材料，有效保障了建筑结构的耐久性。</li></ul><p><img src="'+g+'" alt="图6-9：本土乡土材料"><img src="'+c+'" alt=""><img src="'+h+'" alt=""><img src="'+_+'" alt=""></p><h4 id="_2-近代西式材料" tabindex="-1">2. 近代西式材料 <a class="header-anchor" href="#_2-近代西式材料" aria-label="Permalink to &quot;2. 近代西式材料&quot;">​</a></h4><p>受华侨海外文化交流影响，开平碉楼与村落成为岭南地区最早引入近代西式建筑材料的区域之一，推动了当地建筑材料的革新与升级。</p><ul><li><strong>钢筋混凝土</strong>：大量应用于立园碉楼楼板、柱体，赤坎古镇骑楼柱廊以及塘口墟粮仓主体结构，大幅提升了建筑结构强度与防御性能，是近代侨乡建筑材料革新的核心标志；</li><li><strong>水泥、玻璃、铁艺</strong>：水泥多用于建筑地面、墙面找平与构造加固，玻璃用于门窗构造提升采光性，铁艺则用于装饰栏杆、门窗细节，丰富了建筑形态与功能；</li><li><strong>西式红砖与陶瓷构件</strong>：相较于本土青砖，西式红砖规格更统一、色泽更均匀，搭配西式陶瓷装饰构件，成为中西合璧建筑风格的重要物质载体。</li></ul><p><img src="'+m+'" alt="图10-12：近代西式材料"><img src="'+d+'" alt=""><img src="'+u+'" alt=""></p><h3 id="二-建筑构造工艺与技术特征" tabindex="-1">（二）建筑构造工艺与技术特征 <a class="header-anchor" href="#二-建筑构造工艺与技术特征" aria-label="Permalink to &quot;（二）建筑构造工艺与技术特征&quot;">​</a></h3><p>结合建筑史中岭南民居、近代侨乡建筑构造理论，四大案例的构造工艺可划分为结构构造、围护构造、细部构造三大类别，不同保护模式下构造工艺的保留与改造差异显著。</p><h4 id="_1-结构构造" tabindex="-1">1. 结构构造 <a class="header-anchor" href="#_1-结构构造" aria-label="Permalink to &quot;1. 结构构造&quot;">​</a></h4><p>结构构造是建筑稳定性与功能性的核心，不同案例根据建筑属性与功能需求，形成了差异化的构造体系。</p><ul><li><strong>仓东村乡土建筑</strong>：以传统木构架承重体系为主，墙体仅起围护作用，穿斗式木梁架承接屋面荷载，柱础落地生根，兼具抗震性与通风透气性，符合乡村建筑低成本、实用性的建造原则；碉楼则采用砖石混合承重结构，墙体厚实坚固，内部木楼板分层搭建，构造工艺兼顾防御与居住双重需求；</li><li><strong>立园碉楼与园林建筑</strong>：采用中西混合结构，主体碉楼为钢筋混凝土框架结构，竖向与横向承重能力突出，具备极强的防御性能；园林民居与附属建筑沿用岭南木构架构造，两种结构无缝衔接，体现了近代侨乡建筑构造技术的革新与融合；</li><li><strong>塘口墟粮仓书店</strong>：原粮仓为砖木混合结构，砖石墙体承担主要荷载，木梁架支撑屋面结构，内部空间开阔无多余立柱，适配仓储功能需求；改造过程中保留原有主体结构，仅优化内部荷载分布，凸显功能主义改造的设计理念；</li><li><strong>赤坎古镇骑楼</strong>：采用骑楼式梁柱承重构造，底层为架空连廊结构，由西式混凝土立柱承担竖向荷载，上层为砖木混合结构，屋面采用坡屋顶构造，适配岭南多雨气候与商业沿街使用需求，是近代岭南商业建筑的典型构造体系。</li></ul><h4 id="_2-围护构造" tabindex="-1">2. 围护构造 <a class="header-anchor" href="#_2-围护构造" aria-label="Permalink to &quot;2. 围护构造&quot;">​</a></h4><p>围护构造主要承担隔热、防潮、防水等功能，与建筑使用体验与耐久性密切相关。</p><ul><li><strong>墙体构造</strong>：仓东村民居多采用空斗青砖砌筑，节省材料的同时提升了隔热与通风性能；立园、赤坎古镇骑楼则以实心砖墙为主，增强建筑结构稳固性与密封性；</li><li><strong>屋面构造</strong>：四大案例均有采用坡屋顶构造，铺设陶瓦作为屋面主材，排水坡度契合岭南降雨特征，保障屋面防水性能；仓东村、立园园林碉楼均为钢筋混凝土平顶，设露台、回廊、射击口，实用又兼具防御功能。</li></ul><p><img src="'+k+'" alt="图13-16：围护构造"><img src="'+q+'" alt=""><img src="'+b+'" alt=""><img src="'+f+'" alt=""></p><h4 id="_3-细部构造" tabindex="-1">3. 细部构造 <a class="header-anchor" href="#_3-细部构造" aria-label="Permalink to &quot;3. 细部构造&quot;">​</a></h4><p>细部构造是建筑工艺水平与文化内涵的直接体现，开平碉楼与村落的细部构造兼具地域特色与中西融合特征。</p><ul><li><strong>防潮构造</strong>：传统建筑均在木柱底部设置石材柱础，形成防潮隔离层，避免木柱受潮腐蚀，是岭南潮湿气候下建筑的典型细部处理；</li><li><strong>门窗构造</strong>：采用木质榫卯构造，雕花门窗拼接严密、牢固耐用，西式建筑则搭配玻璃门窗与铁艺装饰，丰富门窗形态；</li><li><strong>防御性构造</strong>：碉楼建筑普遍设置瞭望窗、射击孔等防御构造，墙体加厚处理，强化防御性能，体现了特定历史背景下的建筑功能需求；</li><li><strong>装饰构造</strong>：骑楼廊柱采用西式拱券、线脚构造，搭配灰塑、木雕等中式装饰符号，形成中西合璧的细部装饰风格，是侨乡文化交流的直观体现。</li></ul><p><img src="'+j+'" alt="图17-19：细部构造"><img src="'+P+'" alt=""><img src="'+x+'" alt=""></p><h3 id="三-不同保护模式下材料构造的修复与改造" tabindex="-1">（三）不同保护模式下材料构造的修复与改造 <a class="header-anchor" href="#三-不同保护模式下材料构造的修复与改造" aria-label="Permalink to &quot;（三）不同保护模式下材料构造的修复与改造&quot;">​</a></h3><p>基于文化遗产原真性、完整性、最小干预保护原则，四大案例针对材料与构造采取差异化处理方式，折射出遗产保护的不同理念与实践路径。</p><h4 id="_1-立园" tabindex="-1">1. 立园 <a class="header-anchor" href="#_1-立园" aria-label="Permalink to &quot;1. 立园&quot;">​</a></h4><p>以原真性修复为核心原则，对破损构件采用传统青砖、杉木、糯米灰浆等材料进行原样修补，严格复刻原有砌筑、木作构造工艺，不改变建筑原有材料与构造形态。改造过程中以文物建筑保护规范为依据，最大限度保留建筑历史信息，实现遗产的静态化、专业化保护。</p><p><img src="'+B+'" alt="图20-22：立园修复"><img src="'+C+'" alt=""><img src="'+T+'" alt=""></p><h4 id="_2-仓东村" tabindex="-1">2. 仓东村 <a class="header-anchor" href="#_2-仓东村" aria-label="Permalink to &quot;2. 仓东村&quot;">​</a></h4><p>采用微创修复策略，仅针对破损墙体、腐朽木构件等进行局部修补，修复过程中沿用本土乡土材料与传统构造工艺，不改动建筑主体结构。保留材料自然老化痕迹与原生构造形态，让传统构造适配现代乡村生活需求，实现遗产保护与乡村生活的共生共融。</p><p><img src="'+S+'" alt="图23-24：仓东村修复"><img src="'+A+'" alt=""></p><h4 id="_3-塘口墟粮仓书店" tabindex="-1">3. 塘口墟粮仓书店 <a class="header-anchor" href="#_3-塘口墟粮仓书店" aria-label="Permalink to &quot;3. 塘口墟粮仓书店&quot;">​</a></h4><p>遵循结构保留、材料更新原则，核心保留原有砖石墙体、木梁架等主体结构构造，在此基础上替换腐朽木构件，新增现代轻质隔断、玻璃门窗、钢结构书架等适配书店功能的构造与材料。改造过程中以功能需求为导向，在不破坏主体构造的前提下，实现传统建筑构造的现代利用，体现功能优先的设计理念。</p><p><img src="'+I+'" alt="图25-26：粮仓书店改造"><img src="'+O+'" alt=""></p><h4 id="_4-赤坎古镇" tabindex="-1">4. 赤坎古镇 <a class="header-anchor" href="#_4-赤坎古镇" aria-label="Permalink to &quot;4. 赤坎古镇&quot;">​</a></h4><p>实施风貌统一修复策略，对破损骑楼进行结构加固处理，采用传统材料修复外立面构造与形态；内部空间则替换现代水电管线、保温构造，部分老旧传统材料采用仿古材料替代。改造兼顾遗产风貌保护与文旅商业使用需求，通过构造更新提升建筑舒适度与功能性，实现大规模文旅开发背景下的遗产活化利用。</p><h2 id="四、现存问题与理论思考" tabindex="-1">四、现存问题与理论思考 <a class="header-anchor" href="#四、现存问题与理论思考" aria-label="Permalink to &quot;四、现存问题与理论思考&quot;">​</a></h2><h3 id="一-建造材料与构造保护现存问题" tabindex="-1">（一）建造材料与构造保护现存问题 <a class="header-anchor" href="#一-建造材料与构造保护现存问题" aria-label="Permalink to &quot;（一）建造材料与构造保护现存问题&quot;">​</a></h3><p>通过调研发现，当前开平碉楼与村落建筑材料与构造保护仍存在若干突出问题，制约了遗产的可持续传承。</p><ol><li><p>传统材料技艺传承断层，本土青砖烧制、糯米灰浆调配等传统工艺掌握人员锐减，修复材料难以精准匹配建筑原有材质，影响修复效果与原真性；</p></li><li><p>部分商业性改造项目过度追求外观效果与经济效益，采用现代仿材料替代传统材料，破坏建筑原有的材料肌理与历史信息；</p></li><li><p>社区参与式活态保护的建筑缺乏专业维护力量，乡土材料易出现自然老化、虫蛀、受潮损毁等问题，建筑耐久性面临挑战；</p></li><li><p>整体性文旅开发中，部分改造项目过度调整建筑原有构造逻辑，改变结构受力体系与空间布局，违背遗产保护的核心原则。</p></li></ol><h3 id="二-建筑史与遗产保护理论思考" tabindex="-1">（二）建筑史与遗产保护理论思考 <a class="header-anchor" href="#二-建筑史与遗产保护理论思考" aria-label="Permalink to &quot;（二）建筑史与遗产保护理论思考&quot;">​</a></h3><p><strong>从建筑史视角分析</strong>，开平碉楼与村落的材料与构造，是中国传统岭南乡土建筑向近代西式建筑过渡的重要实物见证，承载着近代侨乡建筑技术革新、中外文化交流的历史信息，是研究岭南近代建筑发展史的关键载体。其材料演变与构造革新，不仅反映了当地社会经济的发展变迁，更体现了岭南建筑文化的包容性与适应性。</p><p><strong>从文化遗产保护理论层面来看</strong>，开平碉楼与村落的材料与构造保护必须坚守原真性、最小干预、可识别性三大核心原则。立园的博物馆化保护、仓东村的活态保护、塘口墟的功能主义改造、赤坎古镇的整体性开发，四种模式无绝对优劣之分，核心在于尊重建筑材料、构造的历史价值，避免破坏性改造与过度商业化干预。</p><p>环境设计的遗产保护与改造工作需以材料构造本体研究为基础，在严格保护核心结构与传统工艺的前提下，结合现代使用需求进行功能适配性优化。通过专业设计与技术手段，实现历史建筑&quot;保护—传承—再利用&quot;的可持续发展路径，让建筑遗产既保留历史底蕴，又能适应现代社会生活。</p><h2 id="五、考察总结" tabindex="-1">五、考察总结 <a class="header-anchor" href="#五、考察总结" aria-label="Permalink to &quot;五、考察总结&quot;">​</a></h2><p>本次以建造材料与构造为核心的开平碉楼考察，系统梳理了岭南侨乡建筑本土与西式材料的应用特征、传统与近代构造工艺的技术逻辑，以及不同保护模式下建筑遗产的修复改造策略。四大案例在材料选用、构造工艺、保护策略上的差异，既凸显了开平碉楼建筑的多元文化价值，也反映出建筑材料与构造技术在文化遗产保护中的核心地位。</p><p>通过本次调研，我深刻认识到，历史建筑保护并非单纯的外观修复，而是对建筑材料、构造工艺、历史信息的全方位传承与活化。作为环境设计专业的学生，在未来的遗产保护与设计实践中，需立足专业理论基础，深入研究建筑本体构造规律，坚守遗产保护核心原则，平衡传统技艺传承与现代使用需求，以专业力量推动开平碉楼这一世界文化遗产的可持续保护与发展。</p>',57)])])}const $=t(W,[["render",y]]);export{R as __pageData,$ as default};
